+function createCanvasTool(): AnyAgentTool {
+  return {
+    label: "Clawdis Canvas",
+    name: "clawdis_canvas",
+    description:
+      "Control node canvases (present/hide/navigate/eval/snapshot/A2UI). Use snapshot to capture the rendered UI.",
+    parameters: CanvasToolSchema,
+    execute: async (_toolCallId, args) => {
+      const params = args as Record<string, unknown>;
+      const action = String(params.action ?? "");
+      const gatewayOpts: GatewayCallOptions = {
+        gatewayUrl:
+          typeof params.gatewayUrl === "string" ? params.gatewayUrl : undefined,
+        gatewayToken:
+          typeof params.gatewayToken === "string"
+            ? params.gatewayToken
+            : undefined,
+        timeoutMs:
+          typeof params.timeoutMs === "number" ? params.timeoutMs : undefined,
+      };
+
+      const nodeId = await resolveNodeId(
+        gatewayOpts,
+        typeof params.node === "string" ? params.node : undefined,
+        true,
+      );
+
+      const invoke = async (command: string, invokeParams?: Record<string, unknown>) =>
+        await callGatewayTool("node.invoke", gatewayOpts, {
+          nodeId,
+          command,
+          params: invokeParams,
+          idempotencyKey: crypto.randomUUID(),
+        });
+
+      switch (action) {
+        case "present": {
+          const placement = {
+            x: typeof params.x === "number" ? params.x : undefined,
+            y: typeof params.y === "number" ? params.y : undefined,
+            width: typeof params.width === "number" ? params.width : undefined,
+            height: typeof params.height === "number" ? params.height : undefined,
+          };
+          const invokeParams: Record<string, unknown> = {};
+          if (typeof params.target === "string" && params.target.trim()) {
+            invokeParams.url = params.target.trim();
+          }
+          if (
+            Number.isFinite(placement.x) ||
+            Number.isFinite(placement.y) ||
+            Number.isFinite(placement.width) ||
+            Number.isFinite(placement.height)
+          ) {
+            invokeParams.placement = placement;
+          }
+          await invoke("canvas.present", invokeParams);
+          return jsonResult({ ok: true });
+        }
+        case "hide":
+          await invoke("canvas.hide", undefined);
+          return jsonResult({ ok: true });
+        case "navigate": {
+          const url = String(params.url ?? "").trim();
+          if (!url) throw new Error("url required");
+          await invoke("canvas.navigate", { url });
+          return jsonResult({ ok: true });
+        }
